#include<bits/stdc++.h>
using namespace std;
const long long mod=1e9+7;
long long n;
char s[100010];
struct matrix
{
    long long a[27][27];
    matrix()
    {
        memset(a,0,sizeof(a));
    }
    friend matrix operator*(const matrix&a,const matrix&b)
    {
        matrix c;
        for(long long i=1;i<=26;i++)
        {
            for(long long j=1;j<=26;j++)
            {
                for(long long k=1;k<=26;k++)
                {
                    c.a[i][j]+=1ll*(a.a[i][k]%mod)*(b.a[k][j]%mod)%mod;
                    c.a[i][j]%=mod;
                }
            }
        }
        return c;
    }
}base,ans;
void fastpow(long long y)
{
    for(long long i=1;i<=26;i++)
    {
        ans.a[i][i]=1;
    }
    while(y)
    {
        if(y%2==1)
        {
            ans=ans*base;
        }
        base=base*base;
        y/=2;
    }
}
int main()
{
    scanf("%lld%s",&n,s+1);
    int m=strlen(s+1);
    for(int i=1;i<=26;i++)
    {
        for(int j=1;j<=26;j++)
        {
            base.a[i][j]=1;
        }
    }
    for(int i=1;i<m;i++)
    {
        base.a[s[i]-'a'+1][s[i+1]-'a'+1]=0;
    }
    fastpow(n-1);
    long long ans=0;
    for(int i=1;i<=26;i++)
    {
        for(int j=1;j<=26;j++)
        {
            ans+=::ans.a[i][j];
            ans%=mod;
        }
    }
    printf("%lld",ans);
    return 0;
}
